require("UI.UI_Curtain")function UIMgr:UI_Curtain_Create(a)local b;if GameMgr.Inst.prefer_language=='chs'or GameMgr.Inst.prefer_language=='chs_t'then b=LuaTools.LoadPrefab('prefab/ui_output/UI_Curtain',a)else b=LuaTools.LoadPrefab('prefab/ui_output/UI_Curtain',a)end;if not b then return nil end;b.gameObject:SetActive(false)local c=UI_Curtain:Create(b)c.curtain=c.transform:Find("Image"):GetComponent(typeof(UnityEngine.UI.Button))c:OnCreate()return c end